  // ── COLOR UTILS ──────────────────────────────────────────────────────────
  function metricColor(val, key) {
    const d=D[key]; if(!d) return '#22c55e';
    const ok = d.inverse ? val>=d.warn : val<=d.warn;
    const crit = d.inverse ? val<=d.crit : val>=d.crit;
    if(crit) return '#ef4444';
    if(ok)   return '#22c55e';
    return '#f59e0b';
  }
  function darken(hex,f){
    const h=parseInt(hex.slice(1),16);
    const r=Math.round(((h>>16)&0xff)*(1-f)), g=Math.round(((h>>8)&0xff)*(1-f)), b=Math.round((h&0xff)*(1-f));
    return '#'+((1<<24)|(r<<16)|(g<<8)|b).toString(16).slice(1);
  }

  // ── MAP ──────────────────────────────────────────────────────────────────
  function initMap() {
    _map = L.map('map',{zoomControl:false,attributionControl:false}).setView([43.27,76.85],11);
    L.tileLayer('https://{s}.basemaps.cartocdn.com/light_all/{z}/{x}/{y}{r}.png',{maxZoom:19,subdomains:'abcd'}).addTo(_map);
    Object.entries(DISTRICTS).forEach(([name,info])=>{
      const dd0=D[_layer]?.districts[name];
      const initFill=dd0?metricColor(dd0.v,_layer):'#94a3b8';
      const poly = L.polygon(info.poly,{
        fillColor:initFill,color:darken(initFill,.3),
        weight:1.5,opacity:.9,fillOpacity:.38,
        bubblingMouseEvents:false
      }).addTo(_map);
      // Bug 3 fix: no bindTooltip — it renders as a rectangle box on click.
      // District name is shown via L.marker label below.
      poly.on('click',(e)=>{
        e.originalEvent.stopPropagation();
        if(_selected && _selected!==name) paintPoly(_selected);
        _selected=name;
        const dd=D[_layer]?.districts[name];
        const fill=dd?metricColor(dd.v,_layer):'#94a3b8';
        _polys[name]?.setStyle({fillColor:fill,fillOpacity:.72,color:'#1e293b',weight:3,opacity:1});
        _polys[name]?.bringToFront();
        openDistrict(name);
      });
      poly.on('mouseover',(e)=>{ e.originalEvent.stopPropagation(); if(_selected!==name) poly.setStyle({fillOpacity:.55,weight:2.5}); });
      poly.on('mouseout',()=>{ if(_selected!==name) paintPoly(name); });

      _polys[name]=poly;
    });
    paintAll();
  }

  function paintPoly(name){
    const dd=D[_layer]?.districts[name]; if(!dd) return;
    const fill=metricColor(dd.v,_layer);
    _polys[name]?.setStyle({fillColor:fill,color:darken(fill,.3),weight:1.5,opacity:.9,fillOpacity:.38});
  }
  function paintAll(){ Object.keys(DISTRICTS).forEach(paintPoly); }

  function setLayer(key){
    _layer=key;
    document.querySelectorAll('.lbtn').forEach(b=>b.classList.remove('active'));
    document.getElementById('lb-'+key)?.classList.add('active');
    const titles={energy:'НАГРУЗКА СЕТИ %',utilities:'ДАВЛЕНИЕ ВОДЫ (бар)',transport:'ИНДЕКС ТРАФИКА (0–10)',urban:'КАЧЕСТВО ВОЗДУХА AQI',tourism:'ПЛОТНОСТЬ ТУРИСТОВ %'};
    const el=document.getElementById('legend-title'); if(el) el.textContent=titles[key]||key;
    paintAll();
  }

  // ── DISTRICT PANEL ───────────────────────────────────────────────────────
  function openDistrict(name){
    _district=name;
    document.getElementById('district-panel').classList.add('open');
    const units={energy:'%',utilities:' bar',transport:'/10',urban:' AQI',tourism:'%'};
    const labels={energy:'Энергетика',utilities:'Коммуналка',transport:'Транспорт',urban:'Гор. среда',tourism:'Туризм'};
    const metrics = Object.keys(D).map(k=>{
      const dd=D[k].districts[name]; if(!dd) return '';
      const c=metricColor(dd.v,k);
      const dir=dd.t>0?`▲${dd.t}`:dd.t<0?`▼${Math.abs(dd.t)}`:'—';
      const dc=dd.t>0?'#ef4444':dd.t<0?'#16a34a':'#94a3b8';
      return `<div class="metric-row"><span class="metric-label">${labels[k]}</span><span class="metric-value" style="color:${c}">${dd.v}${units[k]} <small style="font-size:10px;color:${dc}">${dir}</small></span></div>`;
    }).join('');

    const ai=getAI(name);
    document.getElementById('dp-content').innerHTML=`
      <div class="dp-header">
        <div><div class="dp-title">${name}</div><div class="dp-subtitle">Район Алматы</div></div>
        <button class="dp-close" onclick="App.closeDistrict()">×</button>
      </div>
      <div class="dp-body">
        <div class="section-title">ПОКАЗАТЕЛИ</div>
        ${metrics}
        <div style="margin-top:20px">
          <div class="section-title" style="color:#0ea5e9;display:flex;align-items:center;gap:6px">
            <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="#0ea5e9" stroke-width="2"><circle cx="12" cy="12" r="10"/><path d="M12 8v4m0 4h.01"/></svg>
            АНАЛИЗ ИИ
          </div>
          <div id="dp-ai-load" class="ai-loading" style="margin-top:8px">
            <span class="ai-dot"></span><span class="ai-dot"></span><span class="ai-dot"></span>
            <span class="ai-loading-text">Анализ данных района…</span>
          </div>
          <div id="dp-ai-res" class="ai-result">
            <div class="ai-block"><div class="ai-block-title">ЧТО ПРОИСХОДИТ?</div><div class="ai-block-text">${ai.sit}</div></div>
            <div class="ai-block"><div class="ai-block-title">НАСКОЛЬКО КРИТИЧНО?</div><div class="ai-block-text">${ai.crit}</div></div>
            <div class="ai-actions-block"><div class="ai-actions-title">НЕОБХОДИМЫЕ ДЕЙСТВИЯ</div><div class="ai-actions-text">${ai.act}</div></div>
            <div class="chat-section">
              <div class="chat-label">ЧАТ С ИИ</div>
              <div id="chat-msgs"></div>
              <div class="chat-row">
                <input class="chat-input" id="chat-input" type="text" placeholder="Задать вопрос о районе…" onkeydown="if(event.key==='Enter')App.sendChat()"/>
                <button class="chat-send" onclick="App.sendChat()">→</button>
              </div>
            </div>
          </div>
        </div>
      </div>`;
    setTimeout(()=>{
      const l=document.getElementById('dp-ai-load'), r=document.getElementById('dp-ai-res');
      if(l) l.style.display='none'; if(r) r.style.display='block';
    },1200);
  }

  function closeDistrict(){
    document.getElementById('district-panel').classList.remove('open');
    if(_selected){ paintPoly(_selected); _selected=null; }
    _district=null;
  }

  function getAI(name){
    const map={
      'Ауэзовский':{sit:'Нагрузка сети 94% — критически высокая. Трансформатор Т-07 в тепловом стрессе (87°C при лимите 85°C). 48 000 жителей под риском отключения при увеличении нагрузки на 3%.',crit:'P1 🔴 — Угроза жизни. Под угрозой больницы и пациенты на жизнеобеспечении. Замена трансформатора: ₸85М+.',act:D.energy.act},
      'Алмалинский':{sit:'Два одновременных инцидента: (1) давление воды 2.1 бар (норма 4–6 бар) — прорыв трубы Н-114, затронуто 12 400 квартир; (2) индекс трафика 8.4/10 — пробка на пр. Абая 3.2 км.',crit:'P2/P3 🟠🟡 — Угроза водоснабжению больниц, экстренные службы заблокированы. Экономический ущерб: ₸8М/час.',act:D.utilities.act},
    };
    return map[name]||{sit:`Район ${name} в пределах нормы. Незначительные отклонения, непосредственного риска нет.`,crit:'P6 ⚪ — Низкая серьёзность. Рекомендуется профилактический мониторинг.',act:'1. Продолжить плановый цикл мониторинга.\n2. Дежурному офицеру подтвердить статус на утреннем брифинге.'};
  }

  function sendChat(){
    const inp=document.getElementById('chat-input'), msgs=document.getElementById('chat-msgs');
    if(!inp||!msgs) return;
    const txt=inp.value.trim(); if(!txt) return;
    inp.value='';
    msgs.innerHTML+=`<div class="msg-user">${txt}</div>`;
    msgs.innerHTML+=`<div class="msg-ai" id="typing"><span class="ai-dot"></span><span class="ai-dot"></span><span class="ai-dot"></span></div>`;
    msgs.scrollTop=msgs.scrollHeight;
    fetch('http://localhost:5000/api/chat',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({district:_district,message:txt}),signal:AbortSignal.timeout(30000)})
      .then(r=>r.json()).then(d=>{
        const el=document.getElementById('typing');
        if(el) el.outerHTML=`<div class="msg-ai">${d.response||'Нет ответа от ИИ.'}</div>`;
        msgs.scrollTop=msgs.scrollHeight;
      }).catch(()=>{
        const el=document.getElementById('typing');
        if(el) el.outerHTML=`<div class="msg-ai">Ошибка соединения с ИИ. Проверьте, что сервер запущен.</div>`;
        msgs.scrollTop=msgs.scrollHeight;
      });
  }

  // ── DIGEST ───────────────────────────────────────────────────────────────
  function toggleDigest(){
    _digestOpen=!_digestOpen;
    document.getElementById('digest-body')?.classList.toggle('open',_digestOpen);
    document.getElementById('digest-chevron')?.classList.toggle('rotated',!_digestOpen);
  }

  // ── NAVIGATE ─────────────────────────────────────────────────────────────
  let _pollTimer=null;
  function navigate(page){
    if(_timer){ clearTimeout(_timer); _timer=null; }
    if(_pollTimer){ clearInterval(_pollTimer); _pollTimer=null; }
    document.querySelectorAll('.nav-btn').forEach(b=>b.classList.remove('active'));
    document.getElementById('nav-'+page)?.classList.add('active');
    document.querySelectorAll('.page').forEach(p=>p.classList.remove('active'));
    if(page==='map'){
      document.getElementById('page-map').classList.add('active');
      setTimeout(()=>_map&&_map.invalidateSize(),80);
    } else if(page==='complaints'){
      document.getElementById('page-complaints').classList.add('active');
      renderComplaints();
      _pollTimer=setInterval(renderComplaints,30000);
    } else {
      document.getElementById('page-domain').classList.add('active');
      _domainDistrict='all';
      renderDomain(page);
    }
  }

