  function selectDomainDistrict(dist){
    _domainDistrict=dist;
    if(_currentDomain) renderDomain(_currentDomain);
  }

  // ── DOMAIN DASHBOARD ─────────────────────────────────────────────────────
  function renderDomain(key){
    destroyCharts();
    const d=D[key]; if(!d) return;
    _currentDomain=key;
    const dist=_domainDistrict;
    const isAll=dist==='all';
    const dd=isAll?null:DD[key]?.[dist];
    const kpis=dd?dd.kpis:d.kpis;
    const visAlerts=isAll?d.alerts:(d.alerts.filter(a=>a.l===dist).concat(dd?.alerts||[]));
    const sum=dd?dd.sum:d.sum;
    const crit=dd?dd.crit:d.crit;
    const act=dd?dd.act:d.act;
    const subtitle=isAll?'Алматы':dist;
    const names={energy:'Энергетика',utilities:'Коммуналка (ЖКХ)',transport:'Транспорт',urban:'Городская среда',tourism:'Туризм'};
    const selOpts=['all',...DIST_LIST].map(v=>`<option value="${v}"${v===dist?' selected':''}>${v==='all'?'Все районы':v}</option>`).join('');

    document.getElementById('domain-content').innerHTML=`
      <div style="max-width:1200px;margin:0 auto;padding-bottom:40px">
        <div class="domain-header">
          <div>
            <div class="domain-title-row">
              <div class="domain-accent-bar" style="background:${d.color}"></div>
              <h1 class="domain-title">${names[key]} Dashboard</h1>
            </div>
            <div class="domain-subtitle">Реальное время · ${subtitle} · <span class="mono" id="d-time"></span></div>
          </div>
          <button class="export-btn" onclick="App.exportPDF('${key}')">
            <svg width="13" height="13" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><path d="M21 15v4a2 2 0 01-2 2H5a2 2 0 01-2-2v-4M7 10l5 5 5-5M12 15V3"/></svg>
            Экспорт PDF
          </button>
        </div>

        <div style="display:flex;align-items:center;gap:10px;margin:0 0 18px">
          <span style="font-size:11px;font-weight:600;color:#64748b;text-transform:uppercase;letter-spacing:.05em;flex-shrink:0">Район</span>
          <select onchange="App.selectDomainDistrict(this.value)" style="background:var(--surface);color:var(--text);border:1px solid var(--border);border-radius:6px;padding:6px 10px;font-size:13px;font-family:inherit;cursor:pointer;outline:none">${selOpts}</select>
        </div>

        <div class="kpi-row">${kpis.map(k=>`
          <div class="kpi-card">
            <div class="kpi-label">${k.l}</div>
            <div class="kpi-value" style="color:${d.color}">${k.v}</div>
            <div class="kpi-unit">${k.u}</div>
            <div class="kpi-trend ${k.d}">${k.d==='up'?'▲':k.d==='down'?'▼':'—'} ${k.t}</div>
          </div>`).join('')}</div>

        <div class="charts-row">
          <div class="chart-card">
            <div class="chart-header"><span class="chart-label">ТРЕНД ЗА 24 ЧАСА — ${d.label}</span></div>
            <div style="position:relative;height:180px"><canvas id="chart-ts"></canvas></div>
          </div>
          <div class="chart-card">
            <div class="chart-header">
              <span class="chart-label">ПРОГНОЗ НА 6 ЧАСОВ</span>
              <span class="forecast-badge">ПРОГНОЗ ИИ</span>
            </div>
            <div style="position:relative;height:180px"><canvas id="chart-fc"></canvas></div>
          </div>
        </div>

        <div class="bottom-row">
          <div class="panel-card">
            <div class="panel-label">АНОМАЛИИ И ПРЕДУПРЕЖДЕНИЯ</div>
            ${visAlerts.length?visAlerts.map(a=>`
              <div class="alert-row">
                <span class="badge bp${a.p.toLowerCase()}">${a.p}</span>
                <div><div class="alert-loc">${a.l} <span class="alert-time-text">· ${a.t}</span></div>
                <div class="alert-msg">${a.m}</div></div>
              </div>`).join(''):'<div style="color:var(--text-2);font-size:13px;padding:12px 0">Нет предупреждений для этого района.</div>'}
          </div>
          <div class="panel-card">
            <div class="panel-label">АНАЛИЗ ИИ</div>
            <div id="d-ai-load" class="ai-loading">
              <span class="ai-dot"></span><span class="ai-dot"></span><span class="ai-dot"></span>
              <span class="ai-loading-text">Генерация анализа…</span>
            </div>
            <div id="d-ai-res" class="ai-result">
              <div class="ai-block"><div class="ai-block-title">СВОДКА СИТУАЦИИ</div><div class="ai-block-text">${sum}</div></div>
              <div class="ai-block"><div class="ai-block-title">КРИТИЧНОСТЬ</div><div class="ai-block-text">${crit}</div></div>
              <div class="ai-actions-block" style="border-left:3px solid ${d.color}">
                <div class="ai-actions-title">РЕКОМЕНДУЕМЫЕ ДЕЙСТВИЯ</div>
                <div class="ai-actions-text">${act}</div>
              </div>
            </div>
          </div>
        </div>

        <div class="history-card">
          <div class="panel-label">ЖУРНАЛ АНОМАЛИЙ</div>
          <div class="history-scroll">${(isAll?HISTORY:HISTORY.filter(h=>h.l===dist)).map(h=>`
            <div class="history-row">
              <span class="h-time">${h.t}</span>
              <span class="badge bp${h.p.toLowerCase()}">${h.p}</span>
              <span class="h-loc">${h.l}</span>
              <span class="h-msg">${h.m}</span>
              <span class="s-tag s-${h.s}">${h.s}</span>
            </div>`).join('')||'<div style="color:var(--text-2);font-size:13px;padding:12px 0">Нет записей для этого района.</div>'}
          </div>
        </div>
      </div>`;

    const dtEl=document.getElementById('d-time'); if(dtEl) dtEl.textContent=new Date().toLocaleTimeString('ru-KZ');

    _timer=setTimeout(()=>{
      _timer=null;
      renderCharts(key,d.color,dist);
      const l=document.getElementById('d-ai-load'), r=document.getElementById('d-ai-res');
      if(l) l.style.display='none'; if(r) r.style.display='block';
    },500);
  }
  function destroyCharts(){
    Object.values(_charts).forEach(c=>{ try{c.destroy()}catch(e){} });
    _charts={};
  }

  // Y-axis limits per domain so charts stay within meaningful ranges
  const Y_LIMITS = {
    energy:    {min:0,  max:100},
    utilities: {min:0,  max:8},
    transport: {min:0,  max:10},
    urban:     {min:0,  max:300},
    tourism:   {min:0,  max:100},
  };

  function renderCharts(key,color,dist){
    Chart.defaults.color='#64748b';
    Chart.defaults.font.family="'Inter',system-ui,sans-serif";
    const grid='#e2e8f0', tick='#94a3b8';
    const yl = Y_LIMITS[key] || {};
    const opts=(xMax)=>({
      responsive:true, maintainAspectRatio:false,
      plugins:{legend:{display:false}},
      scales:{
        x:{ticks:{color:tick,font:{size:9},maxTicksLimit:xMax},grid:{color:grid},border:{color:grid}},
        y:{min:yl.min,max:yl.max,ticks:{color:tick,font:{size:9}},grid:{color:grid},border:{color:grid}},
      }
    });

    const ts=document.getElementById('chart-ts');
    if(ts&&!_charts.ts){
      const distVal=(!dist||dist==='all')?null:D[key]?.districts[dist]?.v;
      const chartData=distVal!=null?gen24(distVal,S24[key][0]*0.08+2,D[key]?.districts[dist]?.t||0,Y_LIMITS[key]?.min,Y_LIMITS[key]?.max):S24[key];
      _charts.ts=new Chart(ts,{type:'line',data:{labels:HRS24,datasets:[{data:chartData,borderColor:color,borderWidth:2,backgroundColor:color+'18',fill:true,pointRadius:0,tension:.4}]},options:opts(8)});
    }
    const fc=document.getElementById('chart-fc');
    if(fc&&!_charts.fc){
      const last=S24[key][23], trend={energy:2.5,tourism:4,transport:1.5,urban:.6,utilities:-.8}[key]||1;
      const fl=Y_LIMITS[key]||{};
      _charts.fc=new Chart(fc,{type:'line',data:{labels:HRS6F,datasets:[{data:gen6(last,5,trend,fl.min,fl.max),borderColor:'#a78bfa',borderWidth:2,backgroundColor:'rgba(167,139,250,.1)',borderDash:[6,4],fill:true,pointBackgroundColor:'#a78bfa',pointRadius:4,tension:.4}]},options:opts(7)});
    }
  }

  // ── PDF EXPORT ───────────────────────────────────────────────────────────
  // jsPDF Helvetica has no Cyrillic glyphs — transliterate before writing
  function translit(str) {
    const m={'А':'A','а':'a','Б':'B','б':'b','В':'V','в':'v','Г':'G','г':'g','Д':'D','д':'d',
      'Е':'E','е':'e','Ё':'Yo','ё':'yo','Ж':'Zh','ж':'zh','З':'Z','з':'z','И':'I','и':'i',
      'Й':'Y','й':'y','К':'K','к':'k','Л':'L','л':'l','М':'M','м':'m','Н':'N','н':'n',
      'О':'O','о':'o','П':'P','п':'p','Р':'R','р':'r','С':'S','с':'s','Т':'T','т':'t',
      'У':'U','у':'u','Ф':'F','ф':'f','Х':'Kh','х':'kh','Ц':'Ts','ц':'ts','Ч':'Ch','ч':'ch',
      'Ш':'Sh','ш':'sh','Щ':'Shch','щ':'shch','Ъ':"'",'ъ':"'",'Ы':'Y','ы':'y','Ь':"'",'ь':"'",
      'Э':'E','э':'e','Ю':'Yu','ю':'yu','Я':'Ya','я':'ya',
      'Қ':'Q','қ':'q','Ң':'Ng','ң':'ng','Ғ':'Gh','ғ':'gh','Ү':'U','ү':'u','Ұ':'U','ұ':'u',
      'Ә':'A','ә':'a','І':'I','і':'i','Ө':'O','ө':'o','Һ':'H','һ':'h'};
    return str.split('').map(c=>m[c]||c).join('');
  }
  const T = s => translit(s);

  function exportPDF(key){
    const d=D[key]; const {jsPDF}=window.jspdf;
    const doc=new jsPDF({orientation:'p',unit:'mm',format:'a4'});
    const W=210,M=15; let y=20;
    doc.setFillColor(240,244,248); doc.rect(0,0,W,297,'F');
    doc.setFillColor(14,165,233); doc.rect(0,0,W,13,'F');
    doc.setFont('helvetica','bold'); doc.setFontSize(10); doc.setTextColor(255,255,255);
    doc.text(`SMART CITY ALMATY — ${key.toUpperCase()} REPORT`,M,8.5);
    doc.setFont('helvetica','normal'); doc.text(new Date().toLocaleDateString('en-GB'),W-M,8.5,{align:'right'});
    y=24; doc.setFont('helvetica','bold'); doc.setFontSize(14); doc.setTextColor(30,41,59);
    doc.text(`${key.charAt(0).toUpperCase()+key.slice(1)} Dashboard Report`,M,y); y+=10;
    doc.setFont('helvetica','bold'); doc.setFontSize(9); doc.setTextColor(14,165,233);
    doc.text('KPI SUMMARY',M,y); y+=6;
    doc.setFont('helvetica','normal'); doc.setFontSize(8); doc.setTextColor(30,41,59);
    d.kpis.forEach(k=>{ doc.text(T(`${k.l}: ${k.v} ${k.u}  (${k.t})`),M+3,y); y+=5; }); y+=4;
    doc.setFont('helvetica','bold'); doc.setFontSize(9); doc.setTextColor(239,68,68);
    doc.text('ACTIVE ALERTS',M,y); y+=6;
    doc.setFont('helvetica','normal'); doc.setFontSize(8); doc.setTextColor(30,41,59);
    d.alerts.forEach(a=>{ doc.text(T(`[${a.p}] ${a.t} — ${a.l}: ${a.m}`),M+3,y,{maxWidth:W-M*2-3}); y+=9; }); y+=4;
    doc.setFont('helvetica','bold'); doc.setFontSize(9); doc.setTextColor(14,165,233);
    doc.text('AI ANALYSIS',M,y); y+=6;
    doc.setFont('helvetica','normal'); doc.setFontSize(8); doc.setTextColor(30,41,59);
    const sl=doc.splitTextToSize(T(d.sum),W-M*2); doc.text(sl,M+3,y); y+=sl.length*4.5+4;
    doc.setFont('helvetica','bold'); doc.setFontSize(8); doc.setTextColor(14,165,233);
    doc.text('Actions:',M+3,y); y+=5;
    doc.setFont('helvetica','normal'); doc.setTextColor(30,41,59);
    const al=doc.splitTextToSize(T(d.act),W-M*2); doc.text(al,M+3,y);
    doc.save(`SmartCity_${key}_${new Date().toISOString().slice(0,10)}.pdf`);
  }

